const input = $input.first().json.body || $input.first().json;

// VRF — GUARD + VALIDATE
const isValidUUID = (v) => /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v);
const bookingId = input.old_booking_id || input.booking_id;

let isValid = true;
let error_message = null;

if (!bookingId || !isValidUUID(bookingId)) {
  isValid = false;
  error_message = 'Invalid or missing booking_id (UUID required)';
}
if (isValid && !input.new_start_time) {
  isValid = false;
  error_message = 'Missing required field: new_start_time';
}

const chatId = parseInt(input.chat_id);

return [{
  json: {
    isValid,
    error_message,
    chat_id: isNaN(chatId) ? null : chatId,
    booking_id: bookingId,
    old_booking_id: bookingId,
    start_time: input.new_start_time,
    provider_id: parseInt(input.provider_id) || 1,
    service_id: parseInt(input.service_id) || 1,
    user_email: input.user_email || '',
    user_name: input.user_name || 'Paciente'
  }
}];

// Format reschedule response con message legible para el LLM
const cancelResult = $node["Step 1: Cancel Old"]?.json  || {};
const createResult = $node["Step 2: Create New"]?.json  || {};
const isSuccess    = createResult.success === true;
const newCode      = createResult.data?.booking_code || createResult.data?.new_booking_code || null;
const newTime      = createResult.data?.start_time   || null;

return [{
  json: {
    success: isSuccess,
    message: isSuccess
      ? `Tu cita fue reprogramada correctamente${newCode ? ' (' + newCode + ')' : ''}${newTime ? ' para el ' + newTime : ''}`
      : (createResult.error_message || 'No se pudo reprogramar la cita.'),
    error_code:    isSuccess ? null : (createResult.error_code    || 'RESCHEDULE_ERROR'),
    error_message: isSuccess ? null : (createResult.error_message || 'Reschedule failed'),
    data: {
      old_booking_id:   cancelResult.data?.booking_id   || null,
      old_booking_code: cancelResult.data?.booking_code || null,
      new_booking_id:   createResult.data?.booking_id   || null,
      new_booking_code: newCode,
      status: isSuccess ? 'CONFIRMED' : 'FAILED'
    },
    _meta: { source: 'DB_Reschedule_Booking', timestamp: new Date().toISOString(), version: '3.0.0' }
  }
}];

return [{
  json: {
    success: false,
    error_code: "VALIDATION_ERROR",
    error_message: $json.error_message,
    data: null,
    _meta: { source: "DB_Reschedule_Booking", timestamp: new Date().toISOString(), version: "1.0.0" }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT — Tool-compatible (v3.0.0)
// El AI Agent lee "message" como respuesta legible y "data" para detalles.
const result = $input.first()?.json || {};
const isSuccess = result.success !== false;

// Construir mensaje legible para el LLM
let message = result.message || result.data?.message || null;
if (!message) {
  message = isSuccess
    ? 'Operación completada con éxito.'
    : (result.error_message || result.error_code || 'Error desconocido.');
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (result.error_code    || 'UNKNOWN_ERROR'),
    error_message: isSuccess ? null : (result.error_message || message),
    data:          result.data || null,
    _meta: {
      source:    'DB_RESCHEDULE_BOOKING',
      timestamp: new Date().toISOString(),
      version:   '3.0.0'
    }
  }
}];

const buildData = $('Build Secure JSON').first().json;
return [{
  json: {
    chat_id: buildData.chat_id,
    start_time: buildData.start_time,
    provider_id: buildData.provider_id,
    service_id: buildData.service_id,
    user_name: buildData.user_name,
    user_email: buildData.user_email
  }
}];
